B.DT=new A.ec("assets/image/vicente_carneiro.png","Presidente do CFT Chapa 02: Vicente Carneiro","T\xe9cnico, Engenheiro, CEO do Grupo EGF e Secret\xe1rio de Pol\xedticas Energ\xe9ticas, com s\xf3lida experi\xeancia offshore e viv\xeancia pr\xe1tica na profiss\xe3o. Prop\xf5e um novo CFT com Caixa de Assist\xeancia e Prote\xe7\xe3o ao T\xe9cnico e defesa intransigente das atribui\xe7\xf5es da categoria.")
B.E_=new A.ec("assets/image/abelardo_lopes_de_sousa.png","Conselheiro Federal Chapa 101: Abelardo Lopes De Sousa","Arquiteto do desmembramento da Regi\xe3o Norte e cria\xe7\xe3o do CRT-07. Defende a valoriza\xe7\xe3o dos t\xe9cnicos industriais e a autonomia do conselho para melhor atender a categoria.")
B.DQ=new A.ec("assets/image/jose_ignacio.png","Conselheiro Federal Suplente Chapa 101: Jos\xe9 Ignacio  ","T\xe9cnico em Telecomunica\xe7\xf5es com mais de 40 anos de experi\xeancia em TELEX, Comunica\xe7\xe3o de Dados e Backbone. Especialista em infraestrutura cr\xedtica, defende a confiabilidade e \xe0 continuidade dos servi\xe7os como base da conectividade nacional.")
B.DR=new A.ec("assets/image/ana-paula-fonseca.png","Presidente do CRT 07 Chapa 52: Ana Paula Fonseca","T\xe9cnica em Telecomunica\xe7\xf5es pelo IFPA com mais de 25 anos de experi\xeancia nos setores p\xfablico e privado. Como agente de fiscaliza\xe7\xe3o concursada, defende uma fiscaliza\xe7\xe3o orientadora em vez de punitiva.")
B.DX=new A.ec("assets/image/jefferson_costa.png","Vice-Presidente do CRT 07 Chapa 52: Jefferson Costa","T\xe9cnico em Eletr\xf4nica e especialista em energia solar. Com experi\xeancia na Embratel e ETEMB, defende a qualifica\xe7\xe3o e o registro profissional para valoriza\xe7\xe3o e seguran\xe7a da categoria.")
B.DY=new A.ec("assets/image/francisco_silva_santos.png","Diretor Administrativo do CRT 07 Chapa 52: Francisco Silva Santos","T\xe9cnico em Edifica\xe7\xf5es (IFPA/1975), participou de obras como Mangueir\xe3o e Marco Zero. Atua na defesa do reconhecimento dos t\xe9cnicos industriais no Norte.")
B.DZ=new A.ec("assets/image/arivaldo_lieuthier.png","Diretor Financeiro do CRT 07 Chapa 52: Arivaldo Lieuthier","T\xe9cnico em Telecomunica\xe7\xf5es desde 1978. Paraense, articulou a separa\xe7\xe3o da Regi\xe3o Norte e lutou contra a privatiza\xe7\xe3o da Telebr\xe1s, defendendo o fortalecimento da categoria h\xe1 d\xe9cadas.")
B.DV=new A.ec("assets/image/jose_maria_melo.png","Diretor de Fiscaliza\xe7\xe3o e normas do CRT 07 Chapa 52 : Jos\xe9 Maria Melo","T\xe9cnico com 34 anos de experi\xeancia em eletr\xf4nica e telecomunica\xe7\xf5es (Amaz\xf4nia/Chile). Agente do CRT-02, foca em fiscaliza\xe7\xe3o orientadora e valoriza\xe7\xe3o da categoria.")
